import React, { memo } from "react";
import { Card, CardContent } from "./src/components/ui/card";

const Section = ({ id, children, className = "" }) => (
  <section id={id} className={`mx-auto w-full max-w-7xl px-6 md:px-10 ${className}`}>{children}</section>
);

const GALLERY_IMAGES = [
  {
    src: "/autohooldus-tallinnas-premium.jpg",
    alt: "Premium autohooldus Tallinnas – Nisbel Autostuudio",
    title: "Autohooldus Tallinnas"
  },
  {
    src: "/mb-mootori-taastamine.jpg",
    alt: "Mootori remont Tallinnas – Nisbel Autostuudio",
    title: "Mootori remont Tallinnas"
  },
  {
    src: "/mb-mootori-taastamine-2.jpg",
    alt: "Autodiagnostika Tallinnas – Nisbel Autostuudio",
    title: "Autodiagnostika Tallinnas"
  },
  {
    src: "/asutaja-sander-nisu.jpg",
    alt: "Detailing Tallinnas – Nisbel Autostuudio",
    title: "Detailing Tallinnas"
  },
  {
    src: "/autohooldus-tallinnas-premium.jpg",
    alt: "Rehvitööd Tallinnas – Nisbel Autostuudio",
    title: "Rehvitööd Tallinnas"
  },
  {
    src: "/mb-mootori-taastamine.jpg",
    alt: "Elektritööd Tallinnas – Nisbel Autostuudio",
    title: "Elektritööd Tallinnas"
  }
];

const GallerySection = memo(() => {
  return (
    <Section id="gallery" className="py-12">
      <Card className="mx-auto max-w-6xl rounded-3xl border-white/40 bg-white/80 shadow-xl backdrop-blur dark:bg-slate-900/70 dark:border-slate-800">
        <CardContent className="py-8">
          <h2 className="text-3xl md:text-4xl font-bold tracking-tight text-slate-900 dark:text-slate-100 text-center mb-8">Meie töö galerii</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {GALLERY_IMAGES.map((image, index) => (
              <div key={index} className="relative aspect-square w-full overflow-hidden rounded-3xl shadow-xl ring-1 ring-slate-200 dark:ring-slate-800 group">
                <img
                  src={image.src}
                  alt={image.alt}
                  className="w-full h-full object-cover transition-transform duration-300 group-hover:scale-105"
                  loading="lazy"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
                <div className="absolute bottom-4 left-4 right-4">
                  <p className="text-white text-sm font-semibold bg-black/50 rounded-lg px-3 py-1 inline-block opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                    {image.title}
                  </p>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </Section>
  );
});

GallerySection.displayName = 'GallerySection';

export default GallerySection;
